- payment_status: {{ $json.sheet.payment_status }}
- order_status: {{ $json.sheet.order_status }}
- confirmation_email_sent: {{ $json.sheet.confirmation_email_sent }}
- order_id: {{ $json.sheet.order_id }}
- amount: {{ $json.sheet.amount }}
